mapper.select:
SELECT id, user_id, topic_id, session_type, questions_json, status, correct_count, total_count,
       started_at, completed_at
FROM grammar_library_sessions WHERE id = #{id}

mapper.update:
UPDATE grammar_library_sessions
SET status = 'COMPLETED', correct_count = #{correctCount}, total_count = #{totalCount}, completed_at = now()
WHERE id = #{id}
